const TESTS = [{"id": 1, "title": "Practice Test 1", "sections": [{"name": "Infection Control & Sanitation", "start": 1, "end": 17}, {"name": "Anatomy & Physiology", "start": 18, "end": 34}, {"name": "Hair Structure, Chemistry & Properties", "start": 35, "end": 51}, {"name": "Chemical Texture Services & Color Application", "start": 52, "end": 68}, {"name": "Skin, Scalp Disorders & Client Consultation", "start": 69, "end": 84}, {"name": "Georgia State Law & Salon Regulations", "start": 85, "end": 100}], "questions": [{"id": 1, "section": "Infection Control & Sanitation", "question": "Which term describes a state free of all microorganisms, including spores?", "options": {"A": "Disinfection", "B": "Sanitation", "C": "Sterilization", "D": "Antisepsis"}, "answer": "C"}, {"id": 2, "section": "Infection Control & Sanitation", "question": "What is the primary purpose of using an EPA-registered disinfectant in a salon?", "options": {"A": "Remove visible dirt", "B": "Kill pathogenic organisms on surfaces", "C": "Add fragrance", "D": "Soften implements"}, "answer": "B"}, {"id": 3, "section": "Infection Control & Sanitation", "question": "Blood spills in a salon should be cleaned using:", "options": {"A": "Soap and water only", "B": "A quat-based disinfectant only", "C": "An EPA-registered tuberculocidal disinfectant", "D": "Rubbing alcohol wipe"}, "answer": "C"}, {"id": 4, "section": "Infection Control & Sanitation", "question": "Which of the following is a bloodborne pathogen relevant to salon safety?", "options": {"A": "Tinea", "B": "Hepatitis B", "C": "Pediculosis", "D": "Scabies"}, "answer": "B"}, {"id": 5, "section": "Infection Control & Sanitation", "question": "Implements must be cleaned before they are:", "options": {"A": "Stored", "B": "Disinfected", "C": "Used on the next client", "D": "Both B and C"}, "answer": "D"}, {"id": 6, "section": "Infection Control & Sanitation", "question": "Quaternary ammonium compounds (quats) are commonly used in salons as:", "options": {"A": "Antiseptics", "B": "Disinfectants", "C": "Sterilants", "D": "Emollients"}, "answer": "B"}, {"id": 7, "section": "Infection Control & Sanitation", "question": "The process of removing pathogens and other substances from tools and surfaces is called:", "options": {"A": "Sterilization", "B": "Sanitation (cleaning)", "C": "Immunity", "D": "Disinfection"}, "answer": "B"}, {"id": 8, "section": "Infection Control & Sanitation", "question": "A pathogenic bacteria that grows in clusters and can cause boils is:", "options": {"A": "Bacilli", "B": "Staphylococci", "C": "Spirilla", "D": "Diplococci"}, "answer": "B"}, {"id": 9, "section": "Infection Control & Sanitation", "question": "Which condition is caused by a virus and is highly contagious, requiring service refusal?", "options": {"A": "Alopecia", "B": "Verruca (warts)", "C": "Psoriasis", "D": "Vitiligo"}, "answer": "B"}, {"id": 10, "section": "Infection Control & Sanitation", "question": "Universal Precautions require that a stylist treat all blood and body fluids as:", "options": {"A": "Non-infectious", "B": "Potentially infectious", "C": "Sterile", "D": "Irrelevant to safety"}, "answer": "B"}, {"id": 11, "section": "Infection Control & Sanitation", "question": "How often should whirlpool foot spas be cleaned according to typical state board sanitation rules?", "options": {"A": "Once a week", "B": "After each client and per manufacturer instructions", "C": "Once a month", "D": "Only when visibly dirty"}, "answer": "B"}, {"id": 12, "section": "Infection Control & Sanitation", "question": "Which type of infection results when pathogens spread throughout the body via the bloodstream?", "options": {"A": "Local infection", "B": "General (systemic) infection", "C": "Non-pathogenic infection", "D": "Contact infection"}, "answer": "B"}, {"id": 13, "section": "Infection Control & Sanitation", "question": "Single-use, non-porous items such as neck strips and cotton must be:", "options": {"A": "Disinfected and reused", "B": "Discarded after one use", "C": "Autoclaved", "D": "Rinsed and reused"}, "answer": "B"}, {"id": 14, "section": "Infection Control & Sanitation", "question": "Hand washing before and after every service is a component of:", "options": {"A": "Sterilization", "B": "Standard sanitation/hygiene practice", "C": "Antisepsis only", "D": "Sterilant rotation"}, "answer": "B"}, {"id": 15, "section": "Infection Control & Sanitation", "question": "Which organism classification includes molds and mildews of importance to sanitation?", "options": {"A": "Bacteria", "B": "Fungi", "C": "Parasites", "D": "Viruses"}, "answer": "B"}, {"id": 16, "section": "Infection Control & Sanitation", "question": "MSDS/SDS sheets in a salon provide information about:", "options": {"A": "Client allergies", "B": "Chemical product safety and handling", "C": "Staff schedules", "D": "State board exam content"}, "answer": "B"}, {"id": 17, "section": "Infection Control & Sanitation", "question": "The contact time (dwell time) for a disinfectant refers to:", "options": {"A": "How long it takes to dry", "B": "How long the surface must remain wet with disinfectant to be effective", "C": "The shelf life of the product", "D": "Time before rinsing hands"}, "answer": "B"}, {"id": 18, "section": "Anatomy & Physiology", "question": "The study of the structure of the human body is called:", "options": {"A": "Physiology", "B": "Anatomy", "C": "Histology", "D": "Trichology"}, "answer": "B"}, {"id": 19, "section": "Anatomy & Physiology", "question": "Which system includes the brain, spinal cord, and nerves?", "options": {"A": "Circulatory", "B": "Nervous", "C": "Endocrine", "D": "Lymphatic"}, "answer": "B"}, {"id": 20, "section": "Anatomy & Physiology", "question": "The largest organ of the body is the:", "options": {"A": "Liver", "B": "Skin", "C": "Heart", "D": "Lungs"}, "answer": "B"}, {"id": 21, "section": "Anatomy & Physiology", "question": "Muscles that are not controlled voluntarily, such as the heart, are called:", "options": {"A": "Striated", "B": "Skeletal", "C": "Non-striated (involuntary)", "D": "Flexor"}, "answer": "C"}, {"id": 22, "section": "Anatomy & Physiology", "question": "The scientific study of the skin and its disorders is:", "options": {"A": "Trichology", "B": "Dermatology", "C": "Osteology", "D": "Myology"}, "answer": "B"}, {"id": 23, "section": "Anatomy & Physiology", "question": "Which bone forms the forehead?", "options": {"A": "Occipital", "B": "Parietal", "C": "Frontal", "D": "Temporal"}, "answer": "C"}, {"id": 24, "section": "Anatomy & Physiology", "question": "Blood is pumped through the body by the:", "options": {"A": "Lungs", "B": "Heart", "C": "Kidneys", "D": "Spleen"}, "answer": "B"}, {"id": 25, "section": "Anatomy & Physiology", "question": "Which gland produces sebum (oil)?", "options": {"A": "Sudoriferous gland", "B": "Sebaceous gland", "C": "Thyroid gland", "D": "Pituitary gland"}, "answer": "B"}, {"id": 26, "section": "Anatomy & Physiology", "question": "The system responsible for producing hormones is the:", "options": {"A": "Muscular system", "B": "Skeletal system", "C": "Endocrine system", "D": "Digestive system"}, "answer": "C"}, {"id": 27, "section": "Anatomy & Physiology", "question": "Nerve fibers that carry impulses toward the brain and spinal cord are:", "options": {"A": "Motor (efferent) nerves", "B": "Sensory (afferent) nerves", "C": "Reflex nerves", "D": "Mixed nerves"}, "answer": "B"}, {"id": 28, "section": "Anatomy & Physiology", "question": "The epicranius muscle is responsible for:", "options": {"A": "Chewing", "B": "Raising the eyebrows and wrinkling the forehead", "C": "Closing the eyes", "D": "Moving the ear"}, "answer": "B"}, {"id": 29, "section": "Anatomy & Physiology", "question": "Arteries carry blood:", "options": {"A": "Toward the heart", "B": "Away from the heart", "C": "Only to the lungs", "D": "Only through the lymph system"}, "answer": "B"}, {"id": 30, "section": "Anatomy & Physiology", "question": "The tiny grains of pigment found in the hair and skin are called:", "options": {"A": "Keratin", "B": "Melanin", "C": "Sebum", "D": "Collagen"}, "answer": "B"}, {"id": 31, "section": "Anatomy & Physiology", "question": "Which cranial bone forms the back of the skull?", "options": {"A": "Frontal", "B": "Occipital", "C": "Sphenoid", "D": "Ethmoid"}, "answer": "B"}, {"id": 32, "section": "Anatomy & Physiology", "question": "The muscle that allows you to smile by drawing the corners of the mouth up and back is:", "options": {"A": "Zygomaticus", "B": "Triangularis", "C": "Buccinator", "D": "Mentalis"}, "answer": "A"}, {"id": 33, "section": "Anatomy & Physiology", "question": "Osteology is the study of:", "options": {"A": "Muscles", "B": "Bones", "C": "Nerves", "D": "Blood"}, "answer": "B"}, {"id": 34, "section": "Anatomy & Physiology", "question": "Which of the following is NOT a function of the skin?", "options": {"A": "Protection", "B": "Heat regulation", "C": "Producing red blood cells", "D": "Sensation"}, "answer": "C"}, {"id": 35, "section": "Hair Structure, Chemistry & Properties", "question": "The three layers of the hair shaft, from innermost to outermost, are:", "options": {"A": "Cortex, medulla, cuticle", "B": "Medulla, cortex, cuticle", "C": "Cuticle, cortex, medulla", "D": "Cortex, cuticle, medulla"}, "answer": "B"}, {"id": 36, "section": "Hair Structure, Chemistry & Properties", "question": "Which layer of the hair contains most of the pigment and is responsible for elasticity and strength?", "options": {"A": "Cuticle", "B": "Medulla", "C": "Cortex", "D": "Follicle"}, "answer": "C"}, {"id": 37, "section": "Hair Structure, Chemistry & Properties", "question": "Hair's natural pH is approximately:", "options": {"A": "2.5–3.5", "B": "4.5–5.5", "C": "7.0–8.0", "D": "9.0–10.0"}, "answer": "B"}, {"id": 38, "section": "Hair Structure, Chemistry & Properties", "question": "The chemical bonds broken during a permanent wave that reform on the new curl pattern are:", "options": {"A": "Hydrogen bonds", "B": "Salt bonds", "C": "Disulfide bonds", "D": "Peptide bonds"}, "answer": "C"}, {"id": 39, "section": "Hair Structure, Chemistry & Properties", "question": "Which type of bond is temporarily broken by water or heat (such as blow-drying or wet-setting)?", "options": {"A": "Disulfide bond", "B": "Hydrogen bond", "C": "Peptide bond", "D": "Ionic crosslink only"}, "answer": "B"}, {"id": 40, "section": "Hair Structure, Chemistry & Properties", "question": "Porosity refers to the hair's ability to:", "options": {"A": "Stretch and return", "B": "Absorb moisture/chemicals", "C": "Reflect light", "D": "Resist breakage"}, "answer": "B"}, {"id": 41, "section": "Hair Structure, Chemistry & Properties", "question": "Hair elasticity describes the hair's ability to:", "options": {"A": "Absorb color", "B": "Stretch and return to its original length without breaking", "C": "Resist heat", "D": "Conduct electricity"}, "answer": "B"}, {"id": 42, "section": "Hair Structure, Chemistry & Properties", "question": "The chemical process that relaxes curly hair by breaking disulfide bonds using a strong alkaline product is:", "options": {"A": "Permanent waving", "B": "Chemical hair relaxing", "C": "Bleaching", "D": "Hair pressing"}, "answer": "B"}, {"id": 43, "section": "Hair Structure, Chemistry & Properties", "question": "Level and tone in hair color refer to:", "options": {"A": "Curl pattern and porosity", "B": "Lightness/darkness and color reflect", "C": "pH and viscosity", "D": "Texture and density"}, "answer": "B"}, {"id": 44, "section": "Hair Structure, Chemistry & Properties", "question": "Which type of hair coloring product provides the longest-lasting, most dramatic color change?", "options": {"A": "Temporary color", "B": "Semi-permanent color", "C": "Permanent (oxidative) color", "D": "Vegetable color"}, "answer": "C"}, {"id": 45, "section": "Hair Structure, Chemistry & Properties", "question": "Hydrogen peroxide used with permanent hair color acts as the:", "options": {"A": "Colorant", "B": "Oxidizing agent (developer)", "C": "Conditioner", "D": "Neutralizer"}, "answer": "B"}, {"id": 46, "section": "Hair Structure, Chemistry & Properties", "question": "Overlapping relaxer or perm solution onto previously treated hair can cause:", "options": {"A": "Improved curl", "B": "Hair breakage", "C": "Better porosity", "D": "No effect"}, "answer": "B"}, {"id": 47, "section": "Hair Structure, Chemistry & Properties", "question": "The main protein that makes up the hair shaft is:", "options": {"A": "Collagen", "B": "Keratin", "C": "Elastin", "D": "Melanin"}, "answer": "B"}, {"id": 48, "section": "Hair Structure, Chemistry & Properties", "question": "Coarse hair typically has a ______ cuticle layer compared to fine hair.", "options": {"A": "Thinner", "B": "Thicker", "C": "Identical", "D": "Non-existent"}, "answer": "B"}, {"id": 49, "section": "Hair Structure, Chemistry & Properties", "question": "A \"test curl\" or \"test strand\" is performed during a chemical service to check:", "options": {"A": "Client satisfaction", "B": "Processing progress and results before full application", "C": "Scalp color", "D": "Shampoo residue"}, "answer": "B"}, {"id": 50, "section": "Hair Structure, Chemistry & Properties", "question": "Which factor does NOT affect how a chemical service will process?", "options": {"A": "Hair porosity", "B": "Hair density", "C": "Client's shoe size", "D": "Hair texture"}, "answer": "C"}, {"id": 51, "section": "Hair Structure, Chemistry & Properties", "question": "The neutralization step after a chemical relaxer or perm serves to:", "options": {"A": "Add moisture", "B": "Rebuild disulfide bonds and stop the chemical action", "C": "Lighten the hair", "D": "Remove tangles only"}, "answer": "B"}, {"id": 52, "section": "Chemical Texture Services & Color Application", "question": "Before performing any chemical service, a stylist should always perform a:", "options": {"A": "Client consultation and strand/patch test if indicated", "B": "Full shampoo only", "C": "Blow-dry", "D": "Haircut"}, "answer": "A"}, {"id": 53, "section": "Chemical Texture Services & Color Application", "question": "A predisposition (patch) test is primarily used to check for:", "options": {"A": "Curl strength", "B": "Allergic reaction to a product (e.g., aniline derivative dyes)", "C": "Hair porosity", "D": "Scalp thickness"}, "answer": "B"}, {"id": 54, "section": "Chemical Texture Services & Color Application", "question": "Thio-based (thioglycolate) perm solutions work by:", "options": {"A": "Oxidizing melanin", "B": "Softening and swelling the hair to break disulfide bonds", "C": "Sealing the cuticle", "D": "Adding protein"}, "answer": "B"}, {"id": 55, "section": "Chemical Texture Services & Color Application", "question": "\"Virgin hair\" refers to hair that:", "options": {"A": "Has never been chemically treated", "B": "Has been over-processed", "C": "Is gray", "D": "Has been permed only"}, "answer": "A"}, {"id": 56, "section": "Chemical Texture Services & Color Application", "question": "When double-process blonding, the first step is typically:", "options": {"A": "Toning", "B": "Lightening (bleaching)", "C": "Conditioning", "D": "Neutralizing"}, "answer": "B"}, {"id": 57, "section": "Chemical Texture Services & Color Application", "question": "Which factor determines how quickly a lightener will lift hair color?", "options": {"A": "Volume of developer used", "B": "Client's age", "C": "Salon location", "D": "Time of year"}, "answer": "A"}, {"id": 58, "section": "Chemical Texture Services & Color Application", "question": "A base color that is too warm can often be neutralized using a toner containing:", "options": {"A": "Red tones", "B": "Ash/blue-violet tones", "C": "Gold tones", "D": "No pigment"}, "answer": "B"}, {"id": 59, "section": "Chemical Texture Services & Color Application", "question": "Improper mixing ratios of relaxer and neutralizer can result in:", "options": {"A": "Better curl retention", "B": "Scalp/hair damage or ineffective results", "C": "Faster processing with no risk", "D": "Permanent color enhancement"}, "answer": "B"}, {"id": 60, "section": "Chemical Texture Services & Color Application", "question": "The average time hair color/lightener is left to process is monitored primarily by:", "options": {"A": "The client's preference alone", "B": "Manufacturer's directions and visual/strand checks", "C": "Random guessing", "D": "Salon temperature only"}, "answer": "B"}, {"id": 61, "section": "Chemical Texture Services & Color Application", "question": "Metallic hair dyes found in some over-the-counter products can be dangerous when combined with:", "options": {"A": "Shampoo", "B": "Permanent wave or relaxer solutions", "C": "Conditioner", "D": "Water"}, "answer": "B"}, {"id": 62, "section": "Chemical Texture Services & Color Application", "question": "A \"soft curl perm\" or \"curl reformation\" is typically performed on:", "options": {"A": "Fine, straight Caucasian hair", "B": "Previously relaxed, curly hair to loosen curl pattern", "C": "Gray hair only", "D": "Bleached hair only"}, "answer": "B"}, {"id": 63, "section": "Chemical Texture Services & Color Application", "question": "When applying permanent hair color, new growth (retouch) application should begin:", "options": {"A": "At the scalp on new growth only", "B": "At the ends first", "C": "Randomly throughout", "D": "Only on the crown"}, "answer": "A"}, {"id": 64, "section": "Chemical Texture Services & Color Application", "question": "Which of the following increases the risk of scalp irritation during a chemical relaxer service?", "options": {"A": "Using a base cream/protective barrier", "B": "Scratches or abrasions on the scalp", "C": "Sectioning the hair", "D": "Using a timer"}, "answer": "B"}, {"id": 65, "section": "Chemical Texture Services & Color Application", "question": "Double-processing hair (lightening then toning) increases the risk of:", "options": {"A": "Improved elasticity", "B": "Hair damage/breakage if not managed carefully", "C": "Faster hair growth", "D": "Reduced porosity"}, "answer": "B"}, {"id": 66, "section": "Chemical Texture Services & Color Application", "question": "The purpose of a strand test before color application is to check:", "options": {"A": "Processing time and resulting color/curl", "B": "Client's mood", "C": "Shampoo brand compatibility", "D": "Air temperature"}, "answer": "A"}, {"id": 67, "section": "Chemical Texture Services & Color Application", "question": "Ammonia in permanent hair color functions to:", "options": {"A": "Condition the hair", "B": "Raise the cuticle and allow color molecules to penetrate", "C": "Add shine only", "D": "Neutralize peroxide"}, "answer": "B"}, {"id": 68, "section": "Chemical Texture Services & Color Application", "question": "Which is a sign of over-processed, damaged hair?", "options": {"A": "Increased elasticity", "B": "Mushy, gummy texture when wet and loss of elasticity", "C": "Improved porosity control", "D": "Darker natural color"}, "answer": "B"}, {"id": 69, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A disorder characterized by patchy hair loss, often in circular patterns, is called:", "options": {"A": "Alopecia areata", "B": "Tinea capitis", "C": "Psoriasis", "D": "Trichoptilosis"}, "answer": "A"}, {"id": 70, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Split ends are medically referred to as:", "options": {"A": "Alopecia", "B": "Trichoptilosis", "C": "Fragilitas crinium", "D": "Canities"}, "answer": "B"}, {"id": 71, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which scalp condition is a fungal infection and is contagious, requiring referral to a physician?", "options": {"A": "Dandruff (pityriasis)", "B": "Tinea capitis (ringworm of the scalp)", "C": "Alopecia", "D": "Trichorrhexis nodosa"}, "answer": "B"}, {"id": 72, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Canities is the technical term for:", "options": {"A": "Gray hair", "B": "Split ends", "C": "Excessive hair growth", "D": "Dandruff"}, "answer": "A"}, {"id": 73, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Hypertrichosis refers to:", "options": {"A": "Loss of hair", "B": "Abnormal growth of excess hair", "C": "Gray hair", "D": "Brittle hair"}, "answer": "B"}, {"id": 74, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A client with active head lice (pediculosis) should be:", "options": {"A": "Serviced with extra sanitation", "B": "Refused service and referred to a physician", "C": "Given a haircut only", "D": "Given a chemical service to kill lice"}, "answer": "B"}, {"id": 75, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Comedones (blackheads) are associated with which skin condition?", "options": {"A": "Psoriasis", "B": "Acne (acne vulgaris)", "C": "Eczema", "D": "Rosacea"}, "answer": "B"}, {"id": 76, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A raised, thickened scar resulting from excessive collagen during healing is called a:", "options": {"A": "Macule", "B": "Keloid", "C": "Wheal", "D": "Vesicle"}, "answer": "B"}, {"id": 77, "section": "Skin, Scalp Disorders & Client Consultation", "question": "During a client consultation, which of the following is most important before a chemical service?", "options": {"A": "Client's astrological sign", "B": "Client's hair/scalp history and any allergies or previous chemical treatments", "C": "Client's favorite music", "D": "Weather forecast"}, "answer": "B"}, {"id": 78, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Contact dermatitis in a salon setting is most often caused by:", "options": {"A": "Genetics", "B": "Allergic or irritant reaction to a product", "C": "Sun exposure", "D": "Aging"}, "answer": "B"}, {"id": 79, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Psoriasis is characterized by:", "options": {"A": "Contagious fungal patches", "B": "Red patches covered with silvery-white scales, non-contagious", "C": "Hair loss only", "D": "Bacterial infection"}, "answer": "B"}, {"id": 80, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which is an appropriate response if a stylist notices a suspicious mole or lesion on a client's scalp?", "options": {"A": "Ignore it", "B": "Recommend the client see a physician/dermatologist", "C": "Attempt to remove it", "D": "Apply a chemical treatment over it"}, "answer": "B"}, {"id": 81, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Trichorrhexis nodosa is a condition involving:", "options": {"A": "Swollen, brittle nodes along the hair shaft that can lead to breakage", "B": "Excess oil production", "C": "Gray hair", "D": "Lice infestation"}, "answer": "A"}, {"id": 82, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Rosacea is best described as:", "options": {"A": "A fungal infection", "B": "A chronic condition causing facial redness and visible blood vessels", "C": "A type of dandruff", "D": "A bacterial scalp infection"}, "answer": "B"}, {"id": 83, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Seborrheic dermatitis (severe dandruff) is characterized by:", "options": {"A": "Dry, flaky scalp with possible redness and itching from excess sebum", "B": "Contagious lice", "C": "Permanent hair loss", "D": "Bacterial infection of nails"}, "answer": "A"}, {"id": 84, "section": "Skin, Scalp Disorders & Client Consultation", "question": "When a client discloses they are using isotretinoin (e.g., for severe acne), a stylist should be cautious about:", "options": {"A": "Haircuts", "B": "Chemical/waxing services due to skin fragility", "C": "Blow-drying", "D": "Shampooing"}, "answer": "B"}, {"id": 85, "section": "Georgia State Law & Salon Regulations", "question": "In Georgia, cosmetology licenses are issued and regulated by:", "options": {"A": "The Georgia Department of Labor", "B": "The Georgia State Board of Cosmetology and Barbers", "C": "The Georgia Department of Education", "D": "The local county clerk"}, "answer": "B"}, {"id": 86, "section": "Georgia State Law & Salon Regulations", "question": "How often must a Georgia cosmetology license typically be renewed?", "options": {"A": "Every year", "B": "Every two years", "C": "Every five years", "D": "It never expires"}, "answer": "B"}, {"id": 87, "section": "Georgia State Law & Salon Regulations", "question": "Practicing cosmetology in Georgia without a valid license is:", "options": {"A": "Permitted with a disclaimer", "B": "A violation subject to fines/penalties", "C": "Allowed for family members", "D": "Legal if supervised informally"}, "answer": "B"}, {"id": 88, "section": "Georgia State Law & Salon Regulations", "question": "Georgia salons are subject to inspection by:", "options": {"A": "The IRS", "B": "The Georgia Board of Cosmetology and Barbers/state inspectors", "C": "The Department of Motor Vehicles", "D": "No one"}, "answer": "B"}, {"id": 89, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia cosmetology license must be displayed:", "options": {"A": "At home", "B": "Visibly at the licensee's workstation/place of practice", "C": "Only when requested", "D": "Not required to be displayed"}, "answer": "B"}, {"id": 90, "section": "Georgia State Law & Salon Regulations", "question": "If a Georgia licensee moves and changes their address, they are generally required to:", "options": {"A": "Do nothing", "B": "Notify the state board of the address change", "C": "Retake the exam", "D": "Surrender their license"}, "answer": "B"}, {"id": 91, "section": "Georgia State Law & Salon Regulations", "question": "Which of the following is grounds for disciplinary action against a Georgia cosmetology license?", "options": {"A": "Practicing sanitation properly", "B": "Practicing outside the scope of the license or violating sanitation rules", "C": "Renewing on time", "D": "Attending continuing education"}, "answer": "B"}, {"id": 92, "section": "Georgia State Law & Salon Regulations", "question": "In Georgia, a cosmetology salon must maintain a valid:", "options": {"A": "Salon/shop license in addition to individual practitioner licenses", "B": "Only an individual license", "C": "Federal business permit only", "D": "No licensing is required for the shop"}, "answer": "A"}, {"id": 93, "section": "Georgia State Law & Salon Regulations", "question": "Georgia law requires implements used on clients to be cleaned and disinfected:", "options": {"A": "Once a day", "B": "Between each client", "C": "Once a week", "D": "Only if visibly soiled"}, "answer": "B"}, {"id": 94, "section": "Georgia State Law & Salon Regulations", "question": "Who may legally perform chemical services such as relaxers and permanent waves in Georgia?", "options": {"A": "Anyone working in a salon", "B": "Only licensed cosmetologists or those under proper licensure/supervision as defined by the board", "C": "Salon receptionists", "D": "Unlicensed apprentices without restriction"}, "answer": "B"}, {"id": 95, "section": "Georgia State Law & Salon Regulations", "question": "The purpose of the Georgia State Board of Cosmetology and Barbers includes:", "options": {"A": "Setting hair trends", "B": "Protecting public health and safety through licensing and enforcement", "C": "Running salon marketing", "D": "Setting service prices"}, "answer": "B"}, {"id": 96, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia cosmetology school must be:", "options": {"A": "Approved/licensed by the state board", "B": "Optional to attend", "C": "Unregulated", "D": "Only online"}, "answer": "A"}, {"id": 97, "section": "Georgia State Law & Salon Regulations", "question": "Failure to maintain a clean and sanitary salon in Georgia can result in:", "options": {"A": "A reward", "B": "Citations, fines, or license suspension/revocation", "C": "No consequence", "D": "Automatic license renewal"}, "answer": "B"}, {"id": 98, "section": "Georgia State Law & Salon Regulations", "question": "In Georgia, continuing education requirements for license renewal are:", "options": {"A": "Always mandatory for every license type with no exceptions", "B": "Determined by current Georgia Board of Cosmetology and Barbers rules, which should be verified at renewal", "C": "Never required", "D": "Only for barbers, not cosmetologists"}, "answer": "B"}, {"id": 99, "section": "Georgia State Law & Salon Regulations", "question": "If a client is injured during a service in a Georgia salon, the licensee should:", "options": {"A": "Ignore it", "B": "Follow proper first aid/incident protocol and document as required", "C": "Continue the service regardless", "D": "Deny it happened"}, "answer": "B"}, {"id": 100, "section": "Georgia State Law & Salon Regulations", "question": "The overall goal of Georgia's cosmetology licensing law is to:", "options": {"A": "Limit competition", "B": "Protect consumers by ensuring practitioners meet minimum health, safety, and skill standards", "C": "Increase salon prices", "D": "Regulate hair trends"}, "answer": "B"}]}, {"id": 2, "title": "Practice Test 2", "sections": [{"name": "Infection Control & Sanitation", "start": 1, "end": 17}, {"name": "Anatomy & Physiology", "start": 18, "end": 34}, {"name": "Hair Structure, Chemistry & Properties", "start": 35, "end": 51}, {"name": "Chemical Texture Services & Color Application", "start": 52, "end": 68}, {"name": "Skin, Scalp Disorders & Client Consultation", "start": 69, "end": 84}, {"name": "Georgia State Law & Salon Regulations", "start": 85, "end": 100}], "questions": [{"id": 1, "section": "Infection Control & Sanitation", "question": "Which term refers to the process of destroying most, but not necessarily all, pathogenic organisms on a non-living surface?", "options": {"A": "Sterilization", "B": "Disinfection", "C": "Sanitation", "D": "Immunity"}, "answer": "B"}, {"id": 2, "section": "Infection Control & Sanitation", "question": "Bacteria that are shaped like round balls are classified as:", "options": {"A": "Bacilli", "B": "Spirilla", "C": "Cocci", "D": "Flagella"}, "answer": "C"}, {"id": 3, "section": "Infection Control & Sanitation", "question": "Which of the following is considered a Universal Precaution?", "options": {"A": "Skipping handwashing between clients", "B": "Wearing gloves when in contact with blood/body fluids", "C": "Reusing single-use items", "D": "Ignoring visible spills"}, "answer": "B"}, {"id": 4, "section": "Infection Control & Sanitation", "question": "A wet disinfectant should generally cover an implement for at least:", "options": {"A": "1 minute", "B": "10 minutes (or per manufacturer/EPA label)", "C": "30 seconds", "D": "It's not necessary to time it"}, "answer": "B"}, {"id": 5, "section": "Infection Control & Sanitation", "question": "Non-pathogenic bacteria are:", "options": {"A": "Always harmful", "B": "Generally harmless and may even be beneficial", "C": "Illegal to have in a salon", "D": "The cause of most salon infections"}, "answer": "B"}, {"id": 6, "section": "Infection Control & Sanitation", "question": "What is the correct order of decontamination for reusable metal implements?", "options": {"A": "Disinfect, then clean", "B": "Clean, then disinfect", "C": "Sterilize, then clean", "D": "Store, then clean"}, "answer": "B"}, {"id": 7, "section": "Infection Control & Sanitation", "question": "Which of these is an example of a fomite (object that can spread infection)?", "options": {"A": "A comb used on multiple clients without disinfecting", "B": "A disinfected cape", "C": "A newly opened bottle of shampoo", "D": "Fresh towels from the dryer"}, "answer": "A"}, {"id": 8, "section": "Infection Control & Sanitation", "question": "Hepatitis B is more resistant to destruction on surfaces than HIV, meaning salons should:", "options": {"A": "Use weaker disinfectants", "B": "Follow EPA-registered hospital-grade disinfectant protocols consistently", "C": "Skip disinfection for HIV concerns only", "D": "Only disinfect visibly soiled tools"}, "answer": "B"}, {"id": 9, "section": "Infection Control & Sanitation", "question": "The primary reason acetone/isopropyl alcohol alone is not sufficient for full implement disinfection in many states is:", "options": {"A": "It's too strong", "B": "It may not be EPA-registered as a hospital-level disinfectant for all pathogens", "C": "It damages metal", "D": "It's too expensive"}, "answer": "B"}, {"id": 10, "section": "Infection Control & Sanitation", "question": "Porous items like nail files and buffers should be:", "options": {"A": "Disinfected and reused indefinitely", "B": "Discarded after each client or properly disinfected per state rules", "C": "Shared freely", "D": "Sterilized in an autoclave only"}, "answer": "B"}, {"id": 11, "section": "Infection Control & Sanitation", "question": "Which practice helps prevent cross-contamination from product containers?", "options": {"A": "Double-dipping applicators into product jars", "B": "Using clean spatulas and disposable applicators", "C": "Sharing one applicator for all clients", "D": "Skipping labels on products"}, "answer": "B"}, {"id": 12, "section": "Infection Control & Sanitation", "question": "The term \"immunity\" refers to the body's ability to:", "options": {"A": "Spread infection", "B": "Destroy or resist infection-causing organisms", "C": "Absorb chemicals", "D": "Regenerate hair follicles"}, "answer": "B"}, {"id": 13, "section": "Infection Control & Sanitation", "question": "UV sanitizer cabinets in salons are used to:", "options": {"A": "Sterilize implements completely", "B": "Store already-disinfected implements to keep them clean", "C": "Replace disinfectant solutions entirely", "D": "Dry wet towels"}, "answer": "B"}, {"id": 14, "section": "Infection Control & Sanitation", "question": "Which of the following is true regarding sterilization in most salon settings?", "options": {"A": "It's achieved by simply wiping tools with a towel", "B": "True sterilization typically requires an autoclave, which most salons do not use", "C": "It's the same as sanitation", "D": "It's not important for client safety"}, "answer": "B"}, {"id": 15, "section": "Infection Control & Sanitation", "question": "A client with a visible open sore or active infection on the scalp should be:", "options": {"A": "Serviced with extra gloves", "B": "Referred to a physician and service postponed", "C": "Serviced immediately", "D": "Given a chemical treatment"}, "answer": "B"}, {"id": 16, "section": "Infection Control & Sanitation", "question": "Proper hand hygiene should occur:", "options": {"A": "Once a day", "B": "Before and after each client, and after using the restroom", "C": "Only after visibly dirty tasks", "D": "Only at the start of the shift"}, "answer": "B"}, {"id": 17, "section": "Infection Control & Sanitation", "question": "Which is a correct practice for storing clean, disinfected implements?", "options": {"A": "In an open drawer with dirty tools", "B": "In a clean, covered, labeled container", "C": "In a sink", "D": "Loose in a stylist's pocket"}, "answer": "B"}, {"id": 18, "section": "Anatomy & Physiology", "question": "Physiology is best defined as the study of:", "options": {"A": "The structure of the body", "B": "The functions of the body's systems", "C": "Disease naming", "D": "Hair structure only"}, "answer": "B"}, {"id": 19, "section": "Anatomy & Physiology", "question": "The system that includes the heart and blood vessels is the:", "options": {"A": "Nervous system", "B": "Circulatory system", "C": "Integumentary system", "D": "Skeletal system"}, "answer": "B"}, {"id": 20, "section": "Anatomy & Physiology", "question": "Which of the following is a function of the skeletal system?", "options": {"A": "Digesting food", "B": "Support and protection of internal organs", "C": "Producing hormones", "D": "Regulating body temperature only"}, "answer": "B"}, {"id": 21, "section": "Anatomy & Physiology", "question": "The cell membrane's main function is to:", "options": {"A": "Produce energy", "B": "Enclose and protect the contents of the cell, controlling what passes in/out", "C": "Store DNA only", "D": "Digest waste"}, "answer": "B"}, {"id": 22, "section": "Anatomy & Physiology", "question": "Striated (voluntary) muscles are attached to:", "options": {"A": "Only the skin", "B": "Bones and move them via contraction", "C": "The bloodstream", "D": "Nerve endings only"}, "answer": "B"}, {"id": 23, "section": "Anatomy & Physiology", "question": "The temporal bone is located:", "options": {"A": "At the front of the skull", "B": "At the sides and base of the skull, near the ears", "C": "At the back of the skull", "D": "At the top of the skull only"}, "answer": "B"}, {"id": 24, "section": "Anatomy & Physiology", "question": "The mandible is the:", "options": {"A": "Upper jaw bone", "B": "Lower jaw bone, the largest and strongest bone of the face", "C": "Cheekbone", "D": "Nose bone"}, "answer": "B"}, {"id": 25, "section": "Anatomy & Physiology", "question": "Which gland releases sweat to help regulate body temperature?", "options": {"A": "Sebaceous gland", "B": "Sudoriferous (sweat) gland", "C": "Thyroid gland", "D": "Pituitary gland"}, "answer": "B"}, {"id": 26, "section": "Anatomy & Physiology", "question": "The frontalis muscle is responsible for:", "options": {"A": "Raising the eyebrows and causing horizontal wrinkles across the forehead", "B": "Chewing", "C": "Blinking", "D": "Pursing the lips"}, "answer": "A"}, {"id": 27, "section": "Anatomy & Physiology", "question": "Capillaries are best described as:", "options": {"A": "The largest blood vessels", "B": "Tiny blood vessels connecting arteries and veins, allowing nutrient/gas exchange", "C": "Nerve fibers", "D": "Lymph nodes"}, "answer": "B"}, {"id": 28, "section": "Anatomy & Physiology", "question": "Motor nerves (efferent nerves) carry impulses:", "options": {"A": "From the body to the brain", "B": "From the brain/spinal cord to muscles, causing movement", "C": "Only within the skin", "D": "Only in the eyes"}, "answer": "B"}, {"id": 29, "section": "Anatomy & Physiology", "question": "Which is the primary function of the lymphatic system?", "options": {"A": "Pumping blood", "B": "Removing waste and protecting the body against disease", "C": "Producing bile", "D": "Filtering air"}, "answer": "B"}, {"id": 30, "section": "Anatomy & Physiology", "question": "Melanocytes are cells responsible for producing:", "options": {"A": "Keratin", "B": "Melanin (pigment)", "C": "Collagen", "D": "Sebum"}, "answer": "B"}, {"id": 31, "section": "Anatomy & Physiology", "question": "Which bones form the sides and crown of the skull?", "options": {"A": "Frontal bones", "B": "Parietal bones", "C": "Nasal bones", "D": "Zygomatic bones"}, "answer": "B"}, {"id": 32, "section": "Anatomy & Physiology", "question": "The orbicularis oculi muscle is responsible for:", "options": {"A": "Closing the eyelids", "B": "Opening the mouth", "C": "Raising the upper lip", "D": "Moving the scalp"}, "answer": "A"}, {"id": 33, "section": "Anatomy & Physiology", "question": "Histology is the study of:", "options": {"A": "Bones", "B": "The minute structure of tissues", "C": "Nerves", "D": "The heart only"}, "answer": "B"}, {"id": 34, "section": "Anatomy & Physiology", "question": "Which of these organs is part of the endocrine system and regulates metabolism?", "options": {"A": "Liver", "B": "Thyroid gland", "C": "Spleen", "D": "Pancreas only affects digestion, not endocrine (distractor)"}, "answer": "B"}, {"id": 35, "section": "Hair Structure, Chemistry & Properties", "question": "The outermost layer of the hair shaft, made of overlapping scale-like cells, is the:", "options": {"A": "Medulla", "B": "Cortex", "C": "Cuticle", "D": "Follicle"}, "answer": "C"}, {"id": 36, "section": "Hair Structure, Chemistry & Properties", "question": "Which hair layer, when present, is found only in coarse or thick hair and may be absent in fine hair?", "options": {"A": "Cuticle", "B": "Cortex", "C": "Medulla", "D": "Root sheath"}, "answer": "C"}, {"id": 37, "section": "Hair Structure, Chemistry & Properties", "question": "Density refers to:", "options": {"A": "The diameter of a single hair strand", "B": "The number of hairs per square inch on the scalp", "C": "The hair's ability to absorb moisture", "D": "The natural color of the hair"}, "answer": "B"}, {"id": 38, "section": "Hair Structure, Chemistry & Properties", "question": "Texture of hair refers to:", "options": {"A": "The color depth", "B": "The diameter/coarseness of the hair strand (fine, medium, coarse)", "C": "The scalp's oil level", "D": "The curl pattern only"}, "answer": "B"}, {"id": 39, "section": "Hair Structure, Chemistry & Properties", "question": "Which bond gives hair its temporary shape and is broken by water/heat, reformed by drying?", "options": {"A": "Disulfide bond", "B": "Hydrogen bond", "C": "Salt bond", "D": "Peptide bond"}, "answer": "B"}, {"id": 40, "section": "Hair Structure, Chemistry & Properties", "question": "The main chemical bond broken and reformed to permanently reshape curl pattern is the:", "options": {"A": "Hydrogen bond", "B": "Disulfide (sulfur) bond", "C": "Van der Waals bond", "D": "Ionic bond only"}, "answer": "B"}, {"id": 41, "section": "Hair Structure, Chemistry & Properties", "question": "Low porosity hair is generally characterized by:", "options": {"A": "A raised, open cuticle that absorbs product quickly", "B": "A tight, compact cuticle that resists moisture/chemical penetration", "C": "No cuticle at all", "D": "Always damaged hair"}, "answer": "B"}, {"id": 42, "section": "Hair Structure, Chemistry & Properties", "question": "High porosity hair often results from:", "options": {"A": "Virgin, untreated hair", "B": "Over-processing/chemical damage that raises or breaks the cuticle", "C": "Low density", "D": "Coarse texture only"}, "answer": "B"}, {"id": 43, "section": "Hair Structure, Chemistry & Properties", "question": "Which type of relaxer uses a chemical base that does not require pre-shampooing before application?", "options": {"A": "Sodium hydroxide (lye) relaxer", "B": "Ammonium thioglycolate relaxer only", "C": "Vegetable-based relaxer", "D": "All relaxers require pre-shampooing"}, "answer": "A"}, {"id": 44, "section": "Hair Structure, Chemistry & Properties", "question": "Semi-permanent hair color typically lasts through approximately how many shampoos?", "options": {"A": "1 shampoo", "B": "4–6 shampoos", "C": "20+ shampoos", "D": "It never fades"}, "answer": "B"}, {"id": 45, "section": "Hair Structure, Chemistry & Properties", "question": "In the hair color level system, a lower number (e.g., level 1) represents:", "options": {"A": "The lightest blonde", "B": "The darkest, black shades", "C": "Gray hair only", "D": "A tone, not a level"}, "answer": "B"}, {"id": 46, "section": "Hair Structure, Chemistry & Properties", "question": "Developer/peroxide volume determines:", "options": {"A": "The scent of the color", "B": "The degree of lifting (lightening) power", "C": "The brand of product", "D": "The curl pattern"}, "answer": "B"}, {"id": 47, "section": "Hair Structure, Chemistry & Properties", "question": "Tone in hair color refers to:", "options": {"A": "How dark or light the color is", "B": "The underlying warm or cool color reflect (e.g., gold, ash, red)", "C": "The texture of the hair", "D": "The porosity level"}, "answer": "B"}, {"id": 48, "section": "Hair Structure, Chemistry & Properties", "question": "A patch/predisposition test for aniline derivative tints should be performed:", "options": {"A": "Only if the client requests it", "B": "At least 24–48 hours before application, per manufacturer instructions", "C": "Immediately after application", "D": "Never necessary"}, "answer": "B"}, {"id": 49, "section": "Hair Structure, Chemistry & Properties", "question": "Cross-linking (disulfide bonding) in hair provides:", "options": {"A": "Color", "B": "Strength and shape memory in the cortex", "C": "Shine only", "D": "Scalp protection"}, "answer": "B"}, {"id": 50, "section": "Hair Structure, Chemistry & Properties", "question": "Base color/pigment remaining in the hair after lightening (yellow, orange, red undertones) is known as:", "options": {"A": "Level", "B": "Underlying pigment/contributing pigment", "C": "Porosity", "D": "Tone reflection only"}, "answer": "B"}, {"id": 51, "section": "Hair Structure, Chemistry & Properties", "question": "Overlapping chemical color or lightener onto previously colored hair increases risk of:", "options": {"A": "Even color result", "B": "Breakage, damage, or color banding", "C": "Faster processing with no downside", "D": "No effect"}, "answer": "B"}, {"id": 52, "section": "Chemical Texture Services & Color Application", "question": "Before any chemical relaxer, perm, or tint service, the stylist should complete:", "options": {"A": "A thorough consultation, scalp/hair analysis, and necessary tests", "B": "Only a haircut", "C": "A blow-dry", "D": "Nothing extra is needed"}, "answer": "A"}, {"id": 53, "section": "Chemical Texture Services & Color Application", "question": "The purpose of a \"test curl\" during a perm wrap is to check:", "options": {"A": "Client comfort", "B": "Curl development/processing progress", "C": "Rod color", "D": "Neutralizer scent"}, "answer": "B"}, {"id": 54, "section": "Chemical Texture Services & Color Application", "question": "True or sodium hydroxide relaxers work by:", "options": {"A": "Swelling the hair and breaking disulfide bonds at a high pH without a separate neutralizer step needed for rebonding", "B": "Coloring the hair", "C": "Adding protein bonds", "D": "Sealing the cuticle only"}, "answer": "A"}, {"id": 55, "section": "Chemical Texture Services & Color Application", "question": "\"Relaxed hair\" being treated with a permanent wave (double process) is generally:", "options": {"A": "Recommended for maximum curl", "B": "Discouraged/high risk due to over-processing and breakage", "C": "Required for even color", "D": "Not a concern at all"}, "answer": "B"}, {"id": 56, "section": "Chemical Texture Services & Color Application", "question": "When lightening previously colored (dyed) hair, stylists must be aware that:", "options": {"A": "Lighteners cannot lift artificial color evenly and unexpected results/damage can occur", "B": "It always lightens perfectly evenly", "C": "No strand test is needed", "D": "Only natural hair can be lightened"}, "answer": "A"}, {"id": 57, "section": "Chemical Texture Services & Color Application", "question": "Toners are typically applied:", "options": {"A": "Before lightening", "B": "After lightening, to neutralize unwanted underlying pigment", "C": "Only on virgin dark hair", "D": "Instead of a lightener"}, "answer": "B"}, {"id": 58, "section": "Chemical Texture Services & Color Application", "question": "Which volume of developer is generally used for depositing color with little to no lift?", "options": {"A": "40 volume", "B": "30 volume", "C": "10 volume or lower", "D": "50 volume"}, "answer": "C"}, {"id": 59, "section": "Chemical Texture Services & Color Application", "question": "A stylist mixing tint and developer should always follow:", "options": {"A": "Their own instinct", "B": "The manufacturer's recommended ratio and instructions", "C": "A random ratio", "D": "The client's guess"}, "answer": "B"}, {"id": 60, "section": "Chemical Texture Services & Color Application", "question": "Over-processed hair from repeated chemical services often shows:", "options": {"A": "Increased strength", "B": "Loss of elasticity, mushy texture, and breakage", "C": "Darker natural pigment", "D": "Improved curl memory"}, "answer": "B"}, {"id": 61, "section": "Chemical Texture Services & Color Application", "question": "When performing a chemical relaxer retouch, application should be applied to:", "options": {"A": "The entire strand including previously relaxed hair", "B": "New growth only, avoiding overlap onto previously processed hair", "C": "Only the ends", "D": "Randomly throughout"}, "answer": "B"}, {"id": 62, "section": "Chemical Texture Services & Color Application", "question": "A base or protective cream applied to the scalp before a relaxer service helps:", "options": {"A": "Speed up processing", "B": "Protect the scalp from chemical irritation", "C": "Darken the color", "D": "Add curl"}, "answer": "B"}, {"id": 63, "section": "Chemical Texture Services & Color Application", "question": "Which is a sign that a perm or relaxer should be rinsed/neutralized immediately?", "options": {"A": "The client requests more processing time regardless of hair condition", "B": "The desired curl/straightness has been achieved per test checks, or scalp irritation/discomfort occurs", "C": "The timer has not gone off yet", "D": "The color has not developed"}, "answer": "B"}, {"id": 64, "section": "Chemical Texture Services & Color Application", "question": "Double-process blonding carries higher risk of damage because:", "options": {"A": "It only requires one chemical step", "B": "It involves two chemical processes (lightening and toning), compounding stress on the hair", "C": "It uses no chemicals", "D": "It's always gentler than single-process color"}, "answer": "B"}, {"id": 65, "section": "Chemical Texture Services & Color Application", "question": "A client with chemically relaxed hair wanting a body wave perm should be evaluated for:", "options": {"A": "Nothing special", "B": "Hair's current condition, elasticity, and porosity due to combined chemical risk", "C": "Eye color", "D": "Favorite hairstyle only"}, "answer": "B"}, {"id": 66, "section": "Chemical Texture Services & Color Application", "question": "Which practice reduces the risk of hair breakage during detangling of wet, chemically treated hair?", "options": {"A": "Using a fine-tooth comb starting at the scalp", "B": "Using a wide-tooth comb, starting at the ends and working up", "C": "Brushing vigorously", "D": "Skipping detangling"}, "answer": "B"}, {"id": 67, "section": "Chemical Texture Services & Color Application", "question": "Vegetable/herbal or \"no-lye\" relaxers are often marketed as:", "options": {"A": "Stronger than sodium hydroxide", "B": "Gentler alternatives, though they can still cause damage if misused", "C": "Permanent color products", "D": "Non-chemical treatments"}, "answer": "B"}, {"id": 68, "section": "Chemical Texture Services & Color Application", "question": "The main goal of the neutralization/oxidation step after a thio perm is to:", "options": {"A": "Add shine only", "B": "Harden and fix the new disulfide bonds into the new curl shape", "C": "Remove all curl", "D": "Lighten the hair"}, "answer": "B"}, {"id": 69, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Alopecia is the technical term for:", "options": {"A": "Gray hair", "B": "Hair loss", "C": "Dandruff", "D": "Split ends"}, "answer": "B"}, {"id": 70, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Tinea capitis is:", "options": {"A": "A non-contagious dry scalp condition", "B": "A contagious fungal infection of the scalp requiring physician referral", "C": "A type of hair color allergy", "D": "A permanent hair loss condition"}, "answer": "B"}, {"id": 71, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Fragilitas crinium refers to:", "options": {"A": "Split ends", "B": "Brittle hair that breaks easily", "C": "Gray hair", "D": "Excess oil production"}, "answer": "B"}, {"id": 72, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which condition involves an autoimmune response causing patchy, sudden hair loss?", "options": {"A": "Alopecia areata", "B": "Tinea favosa", "C": "Pediculosis", "D": "Trichoptilosis"}, "answer": "A"}, {"id": 73, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Pediculosis capitis is caused by:", "options": {"A": "A fungus", "B": "Head lice", "C": "Bacteria", "D": "A virus"}, "answer": "B"}, {"id": 74, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Vitiligo is characterized by:", "options": {"A": "Loss of pigmentation in patches of skin", "B": "Excess hair growth", "C": "Dandruff", "D": "Contagious rash"}, "answer": "A"}, {"id": 75, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A wheal (such as from a mosquito bite or hives) is an example of a:", "options": {"A": "Primary skin lesion — an itchy, swollen, temporary bump", "B": "Permanent scar", "C": "Fungal infection", "D": "Bacterial pustule"}, "answer": "A"}, {"id": 76, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Milia are:", "options": {"A": "Small, hard, whitish bumps caused by trapped keratin under the skin", "B": "Contagious lice eggs", "C": "A type of dandruff", "D": "Ingrown hairs"}, "answer": "A"}, {"id": 77, "section": "Skin, Scalp Disorders & Client Consultation", "question": "During consultation, if a client reports a known allergy to PPD (found in many permanent dyes), the stylist should:", "options": {"A": "Proceed with a strong tint anyway", "B": "Avoid aniline-derivative tints and consider PPD-free/alternative options, recommending patch testing", "C": "Ignore the allergy", "D": "Use double the developer"}, "answer": "B"}, {"id": 78, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Furuncles (boils) are:", "options": {"A": "Viral skin lesions", "B": "Bacterial (often staph) infections of hair follicles/skin", "C": "Fungal patches", "D": "Allergic reactions only"}, "answer": "B"}, {"id": 79, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Eczema is generally best described as:", "options": {"A": "A contagious fungal infection", "B": "An inflammatory skin condition causing redness, itching, and irritation, often triggered by allergens/irritants", "C": "A type of lice infestation", "D": "A type of hair loss"}, "answer": "B"}, {"id": 80, "section": "Skin, Scalp Disorders & Client Consultation", "question": "When a client has a known scalp abrasion or cut, the stylist should:", "options": {"A": "Proceed with chemical service as normal", "B": "Avoid chemical services over the compromised area and use caution/refer if needed", "C": "Apply extra bleach", "D": "Ignore it"}, "answer": "B"}, {"id": 81, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Scutula, characteristic of favus (a type of tinea), appear as:", "options": {"A": "Yellow, cup-shaped crusts with a distinct odor", "B": "Painless red bumps", "C": "White flakes only", "D": "Dark spots"}, "answer": "A"}, {"id": 82, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which of these is considered a secondary skin lesion (result of healing/progression)?", "options": {"A": "Macule", "B": "Scar", "C": "Papule", "D": "Vesicle"}, "answer": "B"}, {"id": 83, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A thorough client consultation before any service should include questions about:", "options": {"A": "Client's income", "B": "Allergies, medical history relevant to scalp/skin, previous chemical services, and desired outcome", "C": "Favorite restaurant", "D": "Political opinions"}, "answer": "B"}, {"id": 84, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Verrucae (warts) are caused by:", "options": {"A": "A virus", "B": "A bacteria", "C": "A fungus", "D": "An allergic reaction"}, "answer": "A"}, {"id": 85, "section": "Georgia State Law & Salon Regulations", "question": "In Georgia, which board oversees the licensing of cosmetologists, hair designers, estheticians, and nail technicians?", "options": {"A": "Georgia Board of Cosmetology and Barbers", "B": "Georgia Department of Revenue", "C": "Georgia Board of Nursing", "D": "Georgia Real Estate Commission"}, "answer": "A"}, {"id": 86, "section": "Georgia State Law & Salon Regulations", "question": "To sit for the Georgia cosmetology licensing exam, a candidate typically must complete:", "options": {"A": "No training at all", "B": "Required hours at a licensed/approved cosmetology school (or approved apprenticeship)", "C": "A four-year college degree", "D": "An out-of-state license only"}, "answer": "B"}, {"id": 87, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia salon owner who allows an unlicensed individual to perform cosmetology services is:", "options": {"A": "In compliance if the individual is a family member", "B": "In violation of state licensing law", "C": "Required to report it as a favor", "D": "Following standard practice"}, "answer": "B"}, {"id": 88, "section": "Georgia State Law & Salon Regulations", "question": "Continuing education and license renewal rules for Georgia cosmetology licensees are established by:", "options": {"A": "Each individual salon", "B": "The Georgia Board of Cosmetology and Barbers", "C": "The client", "D": "The federal government"}, "answer": "B"}, {"id": 89, "section": "Georgia State Law & Salon Regulations", "question": "If a Georgia licensee is found practicing with an expired license, they may face:", "options": {"A": "No consequences", "B": "Fines, citations, or other disciplinary action", "C": "An automatic new license", "D": "A promotion"}, "answer": "B"}, {"id": 90, "section": "Georgia State Law & Salon Regulations", "question": "Salons in Georgia are required to keep on premises:", "options": {"A": "Nothing specific", "B": "Proof of shop licensing and evidence of proper sanitation practices for inspection", "C": "Client home addresses only", "D": "Old expired licenses"}, "answer": "B"}, {"id": 91, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia cosmetology license can generally be revoked or suspended for:", "options": {"A": "Renewing on time", "B": "Fraud, gross malpractice, or repeated sanitation violations", "C": "Taking continuing education", "D": "Displaying the license properly"}, "answer": "B"}, {"id": 92, "section": "Georgia State Law & Salon Regulations", "question": "Who is authorized to inspect a Georgia cosmetology salon for compliance?", "options": {"A": "Any customer", "B": "Authorized representatives/inspectors of the state board", "C": "Competing salon owners", "D": "No one; salons are unregulated"}, "answer": "B"}, {"id": 93, "section": "Georgia State Law & Salon Regulations", "question": "Georgia law regarding disinfection of multi-use implements generally requires they be disinfected:", "options": {"A": "Once a month", "B": "Between each and every client", "C": "Only at closing time", "D": "Never, if visibly clean"}, "answer": "B"}, {"id": 94, "section": "Georgia State Law & Salon Regulations", "question": "A cosmetology school operating in Georgia must be:", "options": {"A": "Unlicensed and informal", "B": "Licensed/approved by the appropriate state authority", "C": "Run only online", "D": "Optional for practitioners to attend"}, "answer": "B"}, {"id": 95, "section": "Georgia State Law & Salon Regulations", "question": "If a Georgia licensee changes their legal name, they should typically:", "options": {"A": "Do nothing", "B": "Update their information with the state board", "C": "Get a new license from scratch with a new number every time", "D": "Ignore the update requirement"}, "answer": "B"}, {"id": 96, "section": "Georgia State Law & Salon Regulations", "question": "The purpose of Georgia's shop/salon inspection process is to:", "options": {"A": "Generate revenue only", "B": "Ensure ongoing compliance with health, safety, and sanitation standards", "C": "Rate salon décor", "D": "Determine service pricing"}, "answer": "B"}, {"id": 97, "section": "Georgia State Law & Salon Regulations", "question": "A licensee who moves their practice to a new salon in Georgia should:", "options": {"A": "Do nothing", "B": "Ensure their license is properly displayed/registered at the new location per board rules", "C": "Retake the licensing exam", "D": "Surrender their license"}, "answer": "B"}, {"id": 98, "section": "Georgia State Law & Salon Regulations", "question": "Reciprocity in cosmetology licensing refers to:", "options": {"A": "Getting a discount on renewal", "B": "The process by which a license from another state may be recognized in Georgia under certain conditions", "C": "A type of chemical service", "D": "A disciplinary action"}, "answer": "B"}, {"id": 99, "section": "Georgia State Law & Salon Regulations", "question": "Which best summarizes the intent behind Georgia's cosmetology licensing statutes?", "options": {"A": "Restrict the number of salons", "B": "Safeguard public health and ensure practitioners meet minimum competency and safety standards", "C": "Set uniform pricing", "D": "Promote specific product brands"}, "answer": "B"}, {"id": 100, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia licensee found practicing outside the scope of their specific license type (e.g., performing services not covered by their license) may face:", "options": {"A": "No issue since they are licensed in some capacity", "B": "Disciplinary action for practicing outside their authorized scope", "C": "An automatic scope expansion", "D": "A reward"}, "answer": "B"}]}, {"id": 3, "title": "Practice Test 3", "sections": [{"name": "Infection Control & Sanitation", "start": 1, "end": 17}, {"name": "Anatomy & Physiology", "start": 18, "end": 34}, {"name": "Hair Structure, Chemistry & Properties", "start": 35, "end": 51}, {"name": "Chemical Texture Services & Color Application", "start": 52, "end": 68}, {"name": "Skin, Scalp Disorders & Client Consultation", "start": 69, "end": 84}, {"name": "Georgia State Law & Salon Regulations", "start": 85, "end": 100}], "questions": [{"id": 1, "section": "Infection Control & Sanitation", "question": "Which of the following best defines \"contamination\" in a salon context?", "options": {"A": "A clean, disinfected surface", "B": "The presence of blood, body fluids, or infectious material on a surface/tool", "C": "A fully sterilized implement", "D": "A properly stored towel"}, "answer": "B"}, {"id": 2, "section": "Infection Control & Sanitation", "question": "Rod-shaped bacteria are known as:", "options": {"A": "Cocci", "B": "Bacilli", "C": "Spirilla", "D": "Diplococci"}, "answer": "B"}, {"id": 3, "section": "Infection Control & Sanitation", "question": "Which statement about HIV and salon safety is accurate?", "options": {"A": "HIV is easily spread through casual contact in a salon", "B": "HIV is a bloodborne pathogen requiring standard Universal Precautions, but is fragile outside the body", "C": "HIV cannot be prevented with sanitation practices", "D": "Salons do not need to worry about bloodborne pathogens"}, "answer": "B"}, {"id": 4, "section": "Infection Control & Sanitation", "question": "Autoclaves achieve sterilization using:", "options": {"A": "Cold water", "B": "Pressurized steam at high heat", "C": "UV light only", "D": "Alcohol wipes"}, "answer": "B"}, {"id": 5, "section": "Infection Control & Sanitation", "question": "A disinfectant solution used for tools should be:", "options": {"A": "Reused for weeks without changing", "B": "Changed regularly per manufacturer instructions, especially when visibly dirty or per label", "C": "Only replaced once a year", "D": "Diluted with tap water to save cost"}, "answer": "B"}, {"id": 6, "section": "Infection Control & Sanitation", "question": "Which is an example of proper Universal Precautions during a service?", "options": {"A": "Not washing hands between clients", "B": "Wearing gloves and washing hands when exposure to blood/fluids is possible", "C": "Reusing single-use razors", "D": "Ignoring spills of bodily fluid"}, "answer": "B"}, {"id": 7, "section": "Infection Control & Sanitation", "question": "Non-porous surfaces (like countertops, metal tools) can typically be disinfected with:", "options": {"A": "Only soap and water", "B": "An EPA-registered disinfectant appropriate for the surface", "C": "Nothing; they don't need disinfection", "D": "Only bleach at full strength"}, "answer": "B"}, {"id": 8, "section": "Infection Control & Sanitation", "question": "Cocci bacteria that grow in chains are called:", "options": {"A": "Staphylococci", "B": "Streptococci", "C": "Diplococci", "D": "Bacilli"}, "answer": "B"}, {"id": 9, "section": "Infection Control & Sanitation", "question": "The purpose of an exhaust/ventilation system in a salon is primarily to:", "options": {"A": "Improve lighting", "B": "Reduce exposure to chemical fumes/dust", "C": "Cool the building only", "D": "Sanitize implements"}, "answer": "B"}, {"id": 10, "section": "Infection Control & Sanitation", "question": "If a stylist accidentally cuts a client's skin during a service, the appropriate action is to:", "options": {"A": "Continue the service without addressing it", "B": "Stop, apply appropriate first aid, use gloves, and properly dispose of contaminated materials/disinfect the area", "C": "Ignore it since it's minor", "D": "Use the same tool without cleaning it"}, "answer": "B"}, {"id": 11, "section": "Infection Control & Sanitation", "question": "Which of the following items must be single-use/disposable in most sanitary codes (e.g., orangewood sticks, cotton)?", "options": {"A": "Metal shears", "B": "Porous, single-use items that cannot be effectively disinfected", "C": "Glass bowls", "D": "Plastic clips"}, "answer": "B"}, {"id": 12, "section": "Infection Control & Sanitation", "question": "General infection occurs when:", "options": {"A": "Pathogens are confined to one area (like a pimple)", "B": "Pathogens spread through the bloodstream affecting the whole body", "C": "No pathogens are present", "D": "Only the skin surface is affected"}, "answer": "B"}, {"id": 13, "section": "Infection Control & Sanitation", "question": "Standard practice for cleaning a hair styling chair between clients includes:", "options": {"A": "Never cleaning it", "B": "Wiping down and disinfecting surfaces that contact clients", "C": "Replacing the chair", "D": "Vacuuming only"}, "answer": "B"}, {"id": 14, "section": "Infection Control & Sanitation", "question": "Sanitizer/disinfectant label \"contact time\" instructions must be followed because:", "options": {"A": "It's just a suggestion", "B": "Effectiveness against pathogens depends on the solution remaining on the surface for the specified time", "C": "It affects the color of the solution only", "D": "It has no bearing on effectiveness"}, "answer": "B"}, {"id": 15, "section": "Infection Control & Sanitation", "question": "Storing combs and brushes after disinfection should be done in a:", "options": {"A": "Wet sink", "B": "Clean, dry, covered container", "C": "Open drawer with dirty tools", "D": "Client's bag"}, "answer": "B"}, {"id": 16, "section": "Infection Control & Sanitation", "question": "First aid kits in a licensed salon should be:", "options": {"A": "Absent", "B": "Available, stocked, and accessible for minor injuries", "C": "Locked away and inaccessible", "D": "Optional decoration"}, "answer": "B"}, {"id": 17, "section": "Infection Control & Sanitation", "question": "Which best describes \"sanitation\" as used in salon sanitary codes?", "options": {"A": "Killing all microorganisms including spores", "B": "The process of cleaning to reduce the number of pathogens and reduce risk of infection", "C": "A synonym for sterilization only", "D": "Not applicable to salons"}, "answer": "B"}, {"id": 18, "section": "Anatomy & Physiology", "question": "Cells are considered the basic unit of:", "options": {"A": "Chemical reactions only", "B": "Structure and function in living organisms", "C": "Hair growth only", "D": "Blood clotting only"}, "answer": "B"}, {"id": 19, "section": "Anatomy & Physiology", "question": "The integumentary system consists of:", "options": {"A": "The skin, hair, nails, and glands", "B": "The heart and blood vessels", "C": "The brain and spinal cord", "D": "The bones only"}, "answer": "A"}, {"id": 20, "section": "Anatomy & Physiology", "question": "Which system transports oxygen and nutrients throughout the body?", "options": {"A": "Skeletal system", "B": "Circulatory system", "C": "Muscular system", "D": "Excretory system"}, "answer": "B"}, {"id": 21, "section": "Anatomy & Physiology", "question": "The skull is composed of how many bones (cranial and facial combined, generally taught)?", "options": {"A": "14", "B": "22", "C": "33", "D": "8"}, "answer": "B"}, {"id": 22, "section": "Anatomy & Physiology", "question": "The zygomatic bones are commonly known as the:", "options": {"A": "Jaw bones", "B": "Cheekbones", "C": "Nasal bones", "D": "Brow bones"}, "answer": "B"}, {"id": 23, "section": "Anatomy & Physiology", "question": "Which muscle is used for pursing the lips (as in whistling)?", "options": {"A": "Orbicularis oris", "B": "Frontalis", "C": "Masseter", "D": "Platysma"}, "answer": "A"}, {"id": 24, "section": "Anatomy & Physiology", "question": "The masseter and temporalis muscles are primarily responsible for:", "options": {"A": "Blinking", "B": "Chewing (mastication)", "C": "Raising eyebrows", "D": "Nostril movement"}, "answer": "B"}, {"id": 25, "section": "Anatomy & Physiology", "question": "Veins are blood vessels that carry blood:", "options": {"A": "Away from the heart only", "B": "Back toward the heart", "C": "Only within the brain", "D": "Only through the skin"}, "answer": "B"}, {"id": 26, "section": "Anatomy & Physiology", "question": "The pituitary gland is often called the \"master gland\" because it:", "options": {"A": "Produces sweat", "B": "Regulates other endocrine glands via hormone signals", "C": "Pumps blood", "D": "Produces melanin"}, "answer": "B"}, {"id": 27, "section": "Anatomy & Physiology", "question": "Reflex actions, such as pulling a hand away from heat, are controlled by:", "options": {"A": "The endocrine system only", "B": "The nervous system, often via reflex arcs", "C": "The muscular system alone", "D": "The circulatory system"}, "answer": "B"}, {"id": 28, "section": "Anatomy & Physiology", "question": "The five basic types of movement produced by muscle contraction include:", "options": {"A": "Only expansion", "B": "Flexion, extension, abduction, adduction, rotation", "C": "Only digestion-related movement", "D": "Only involuntary movement"}, "answer": "B"}, {"id": 29, "section": "Anatomy & Physiology", "question": "Which of the following best describes the function of the lymph nodes?", "options": {"A": "Pump blood through the body", "B": "Filter lymph fluid and help fight infection", "C": "Produce hormones", "D": "Digest food"}, "answer": "B"}, {"id": 30, "section": "Anatomy & Physiology", "question": "The dermis is:", "options": {"A": "The outermost layer of skin", "B": "The inner layer of skin containing blood vessels, nerves, and follicles", "C": "A layer of hair only", "D": "Part of the skeletal system"}, "answer": "B"}, {"id": 31, "section": "Anatomy & Physiology", "question": "Keratin is a protein found in:", "options": {"A": "Blood only", "B": "Hair, skin, and nails", "C": "The brain only", "D": "Muscle tissue only"}, "answer": "B"}, {"id": 32, "section": "Anatomy & Physiology", "question": "Which nerve is primarily responsible for movement/sensation in the face and is important for cosmetologists to understand for facial services?", "options": {"A": "Sciatic nerve", "B": "Fifth cranial (trigeminal) and seventh cranial (facial) nerves", "C": "Optic nerve only", "D": "Vagus nerve only"}, "answer": "B"}, {"id": 33, "section": "Anatomy & Physiology", "question": "Sebaceous glands are connected to:", "options": {"A": "Bones", "B": "Hair follicles, secreting sebum onto the hair/skin", "C": "The lymphatic system only", "D": "Nerve endings exclusively"}, "answer": "B"}, {"id": 34, "section": "Anatomy & Physiology", "question": "Which best describes the epidermis?", "options": {"A": "The deepest layer of skin containing blood vessels", "B": "The outer, protective layer of skin with no blood vessels of its own", "C": "A muscle layer", "D": "Part of the skeletal system"}, "answer": "B"}, {"id": 35, "section": "Hair Structure, Chemistry & Properties", "question": "Which layer of the hair is responsible for the hair's shine and acts as a protective outer layer?", "options": {"A": "Medulla", "B": "Cortex", "C": "Cuticle", "D": "Papilla"}, "answer": "C"}, {"id": 36, "section": "Hair Structure, Chemistry & Properties", "question": "The hair bulb surrounds and nourishes:", "options": {"A": "The cortex only", "B": "The dermal papilla, which supplies blood/nutrients for hair growth", "C": "The cuticle only", "D": "The scalp surface"}, "answer": "B"}, {"id": 37, "section": "Hair Structure, Chemistry & Properties", "question": "Hair growth occurs in cycles; the active growth phase is called:", "options": {"A": "Catagen", "B": "Anagen", "C": "Telogen", "D": "Dormant phase"}, "answer": "B"}, {"id": 38, "section": "Hair Structure, Chemistry & Properties", "question": "The resting phase of the hair growth cycle, before shedding, is called:", "options": {"A": "Anagen", "B": "Catagen", "C": "Telogen", "D": "Active phase"}, "answer": "C"}, {"id": 39, "section": "Hair Structure, Chemistry & Properties", "question": "Which factor most directly affects how a chemical service (perm, relaxer, color) will process on a given client's hair?", "options": {"A": "The client's shoe size", "B": "Hair's porosity, texture, and density", "C": "The salon's paint color", "D": "Time of day only"}, "answer": "B"}, {"id": 40, "section": "Hair Structure, Chemistry & Properties", "question": "Salt bonds in the hair are:", "options": {"A": "Permanent bonds unaffected by pH", "B": "Weaker, pH-related bonds within the cortex, part of the hair's side bonds", "C": "Found only in the cuticle", "D": "The strongest bond type overall"}, "answer": "B"}, {"id": 41, "section": "Hair Structure, Chemistry & Properties", "question": "Which best defines \"elasticity\" in the context of hair analysis?", "options": {"A": "The hair's ability to absorb chemicals", "B": "The hair's ability to stretch and return to its original length without breaking", "C": "The hair's natural color depth", "D": "The number of hairs per square inch"}, "answer": "B"}, {"id": 42, "section": "Hair Structure, Chemistry & Properties", "question": "Fine hair, due to a smaller diameter, often:", "options": {"A": "Processes chemical services more slowly than coarse hair", "B": "Processes chemical services more quickly and may need shorter timing", "C": "Cannot be chemically treated", "D": "Has no cuticle layer"}, "answer": "B"}, {"id": 43, "section": "Hair Structure, Chemistry & Properties", "question": "Overly porous (damaged) hair tends to:", "options": {"A": "Resist chemical processing entirely", "B": "Absorb chemicals/color too quickly and may over-process or turn out uneven", "C": "Never absorb any product", "D": "Have no risk during chemical services"}, "answer": "B"}, {"id": 44, "section": "Hair Structure, Chemistry & Properties", "question": "The term \"virgin hair\" as used in a consultation means the hair:", "options": {"A": "Has been previously bleached", "B": "Has never received a chemical service", "C": "Is naturally curly only", "D": "Has been previously relaxed"}, "answer": "B"}, {"id": 45, "section": "Hair Structure, Chemistry & Properties", "question": "Ammonia-free hair colors typically use an alternative alkalizing ingredient such as:", "options": {"A": "Sodium hydroxide", "B": "Ethanolamine or similar milder alkalizers", "C": "Hydrogen peroxide only", "D": "Thioglycolic acid"}, "answer": "B"}, {"id": 46, "section": "Hair Structure, Chemistry & Properties", "question": "When performing a color correction to fix overly brassy/orange tones, a stylist would typically apply a toner with:", "options": {"A": "Orange-based pigment", "B": "Blue or violet-based pigment to counteract warmth", "C": "No pigment at all", "D": "Red-based pigment"}, "answer": "B"}, {"id": 47, "section": "Hair Structure, Chemistry & Properties", "question": "In the \"law of color\" (color theory) used in the salon, blue and orange are considered:", "options": {"A": "Analogous colors", "B": "Complementary colors that neutralize each other", "C": "Primary colors", "D": "Unrelated colors"}, "answer": "B"}, {"id": 48, "section": "Hair Structure, Chemistry & Properties", "question": "Primary colors used in hair color theory are:", "options": {"A": "Red, yellow, blue", "B": "Red, green, purple", "C": "Orange, green, violet", "D": "Black, white, gray"}, "answer": "A"}, {"id": 49, "section": "Hair Structure, Chemistry & Properties", "question": "Secondary colors in color theory (formed by mixing two primaries) include:", "options": {"A": "Red, yellow, blue", "B": "Green, orange, violet", "C": "Black and white", "D": "Only gray tones"}, "answer": "B"}, {"id": 50, "section": "Hair Structure, Chemistry & Properties", "question": "Hair with a high percentage of gray/white hair often requires:", "options": {"A": "No special consideration", "B": "Special consideration for coverage since gray hair can be more resistant and may need longer processing", "C": "Less developer", "D": "A weaker relaxer only"}, "answer": "B"}, {"id": 51, "section": "Hair Structure, Chemistry & Properties", "question": "Cuticle layer condition directly impacts:", "options": {"A": "Only hair color", "B": "Porosity and how easily chemicals/moisture penetrate the hair shaft", "C": "Only hair length", "D": "Muscle tone"}, "answer": "B"}, {"id": 52, "section": "Chemical Texture Services & Color Application", "question": "A thorough hair and scalp analysis before a chemical service should evaluate:", "options": {"A": "Client's astrology", "B": "Porosity, elasticity, density, texture, and scalp condition", "C": "Client's favorite shampoo brand", "D": "Weather only"}, "answer": "B"}, {"id": 53, "section": "Chemical Texture Services & Color Application", "question": "Test curls during perm processing help the stylist determine:", "options": {"A": "The final color", "B": "Whether the desired curl has developed and if it's time to neutralize", "C": "The scalp's pH only", "D": "Client satisfaction with pricing"}, "answer": "B"}, {"id": 54, "section": "Chemical Texture Services & Color Application", "question": "Low pH (acid-balanced) perms are generally considered:", "options": {"A": "Harsher and faster processing than alkaline perms", "B": "Gentler, often with slower processing and requiring heat, better for color-treated/fragile hair", "C": "Identical to alkaline perms in every way", "D": "Not real perms"}, "answer": "B"}, {"id": 55, "section": "Chemical Texture Services & Color Application", "question": "Chemical hair relaxers and permanent waves should generally not be combined in the same session because:", "options": {"A": "There is no risk in combining them", "B": "The cumulative chemical stress significantly raises the risk of severe damage/breakage", "C": "They cancel each other out safely", "D": "It's required for the best results"}, "answer": "B"}, {"id": 56, "section": "Chemical Texture Services & Color Application", "question": "During a color consultation, if a client wants to go from dark brown to platinum blonde in one session, the stylist should:", "options": {"A": "Proceed without discussion", "B": "Discuss realistic expectations, potential need for multiple sessions, and hair health risks", "C": "Guarantee it can be done safely in one visit regardless of hair condition", "D": "Refuse to discuss it"}, "answer": "B"}, {"id": 57, "section": "Chemical Texture Services & Color Application", "question": "Filler products used in color correction help to:", "options": {"A": "Strip all color from hair", "B": "Replace lost pigment/deposit tone evenly before applying a new color, especially on porous or previously lightened hair", "C": "Neutralize odor", "D": "Add curl"}, "answer": "B"}, {"id": 58, "section": "Chemical Texture Services & Color Application", "question": "Which volume of developer carries the highest risk of scalp/hair damage if misused?", "options": {"A": "10 volume", "B": "20 volume", "C": "40 volume", "D": "Volume has no bearing on risk"}, "answer": "C"}, {"id": 59, "section": "Chemical Texture Services & Color Application", "question": "When mixing chemical relaxers, using more product than the manufacturer recommends will:", "options": {"A": "Improve safety", "B": "Not necessarily improve results and can increase risk of damage", "C": "Guarantee better curl relaxation", "D": "Have no effect"}, "answer": "B"}, {"id": 60, "section": "Chemical Texture Services & Color Application", "question": "A \"band\" of uneven color (color banding) often results from:", "options": {"A": "Overlapping color application unevenly onto previously treated hair", "B": "Even, consistent application", "C": "Using too little product", "D": "Perfect application technique"}, "answer": "A"}, {"id": 61, "section": "Chemical Texture Services & Color Application", "question": "The primary reason for performing an incompatibility test before certain chemical services is to check for:", "options": {"A": "Client's mood", "B": "Presence of metallic salts or other substances that could react dangerously with the chemical service", "C": "Hair length", "D": "Scalp temperature"}, "answer": "B"}, {"id": 62, "section": "Chemical Texture Services & Color Application", "question": "When performing a retouch relaxer application, care should be taken to avoid overlapping onto previously relaxed hair because:", "options": {"A": "It improves curl pattern", "B": "It can cause severe breakage/damage from over-processing already-processed hair", "C": "It has no effect", "D": "It's required for even results"}, "answer": "B"}, {"id": 63, "section": "Chemical Texture Services & Color Application", "question": "A client with a recent chemical burn/scalp irritation from a previous service should:", "options": {"A": "Get another chemical service right away", "B": "Allow the scalp to heal and be evaluated before further chemical services", "C": "Ignore the irritation", "D": "Have a stronger chemical applied"}, "answer": "B"}, {"id": 64, "section": "Chemical Texture Services & Color Application", "question": "Which is a benefit of using lower volume developers when only depositing color (no lift needed)?", "options": {"A": "Faster processing with more damage risk", "B": "Gentler processing with less potential for scalp/hair irritation", "C": "No color deposit at all", "D": "Guaranteed lightening"}, "answer": "B"}, {"id": 65, "section": "Chemical Texture Services & Color Application", "question": "The \"law of color\" concept of \"level\" in hair coloring refers to:", "options": {"A": "The tone/reflect only", "B": "The lightness or darkness of a color on a numbered scale (commonly 1–10)", "C": "The texture of hair", "D": "The curl pattern"}, "answer": "B"}, {"id": 66, "section": "Chemical Texture Services & Color Application", "question": "Semi-permanent hair color differs from permanent color in that it:", "options": {"A": "Requires mixing with developer for a chemical reaction that permanently alters the hair", "B": "Typically coats the hair shaft without significant lifting, fading gradually over several shampoos", "C": "Cannot be used on any hair type", "D": "Lasts forever"}, "answer": "B"}, {"id": 67, "section": "Chemical Texture Services & Color Application", "question": "If a strand test shows the hair is processing much faster than expected, the stylist should:", "options": {"A": "Ignore it and continue as planned", "B": "Monitor closely and adjust timing/process to prevent damage", "C": "Add more chemical", "D": "Double the processing time regardless"}, "answer": "B"}, {"id": 68, "section": "Chemical Texture Services & Color Application", "question": "The final step after color or chemical texture services, which helps close the cuticle and restore pH balance, typically involves:", "options": {"A": "Skipping conditioner", "B": "Using a pH-balanced shampoo/conditioner formulated for chemically treated hair", "C": "Using a strong alkaline product", "D": "Applying more chemical solution"}, "answer": "B"}, {"id": 69, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Trichoptilosis is another term for:", "options": {"A": "Gray hair", "B": "Split ends", "C": "Head lice", "D": "Dandruff"}, "answer": "B"}, {"id": 70, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which scalp/hair condition is NOT contagious and can typically still be serviced with caution?", "options": {"A": "Tinea capitis (ringworm)", "B": "Alopecia (hair loss, non-infectious types)", "C": "Pediculosis (lice)", "D": "Active impetigo"}, "answer": "B"}, {"id": 71, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Excessively dry, flaking scalp without infection is generally referred to as:", "options": {"A": "Tinea capitis", "B": "Pityriasis (dandruff)", "C": "Furuncle", "D": "Pediculosis"}, "answer": "B"}, {"id": 72, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which of these skin conditions is an autoimmune condition, not contagious, and results in lighter patches of skin?", "options": {"A": "Vitiligo", "B": "Tinea", "C": "Impetigo", "D": "Scabies"}, "answer": "A"}, {"id": 73, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Impetigo is:", "options": {"A": "A non-contagious dry skin condition", "B": "A contagious bacterial skin infection", "C": "A type of hair loss", "D": "A fungal nail condition"}, "answer": "B"}, {"id": 74, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A pustule is best described as:", "options": {"A": "A flat spot with no elevation", "B": "A raised, pus-filled lesion", "C": "A permanent scar", "D": "A patch of missing pigment"}, "answer": "B"}, {"id": 75, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which of the following would require a stylist to refuse service and refer the client to a physician?", "options": {"A": "Mild dandruff", "B": "An active, contagious scalp infection (e.g., ringworm, active lice)", "C": "Slightly oily scalp", "D": "Gray hair"}, "answer": "B"}, {"id": 76, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Cysts, as a type of skin lesion, are best described as:", "options": {"A": "Flat, discolored spots", "B": "Closed sacs containing fluid or semi-fluid material, often below the skin's surface", "C": "Scaly patches only", "D": "Contagious rashes only"}, "answer": "B"}, {"id": 77, "section": "Skin, Scalp Disorders & Client Consultation", "question": "A comprehensive consultation for a new client should always include a review of:", "options": {"A": "Only the desired haircut length", "B": "Health history relevant to services, allergies, current medications affecting skin/hair, and prior chemical treatments", "C": "Favorite TV shows", "D": "Nothing beyond the requested style"}, "answer": "B"}, {"id": 78, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Steatoma (wen) refers to:", "options": {"A": "A sebaceous cyst, a subcutaneous tumor of the sebaceous gland", "B": "A type of lice", "C": "A bacterial infection", "D": "A viral wart"}, "answer": "A"}, {"id": 79, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Rosacea flare-ups can sometimes be aggravated by:", "options": {"A": "Cold water only", "B": "Heat, certain chemicals, or friction during services, requiring gentle handling", "C": "Nothing; it's unaffected by external factors", "D": "Only diet"}, "answer": "B"}, {"id": 80, "section": "Skin, Scalp Disorders & Client Consultation", "question": "When in doubt about whether a skin or scalp condition is safe to service, the appropriate action is to:", "options": {"A": "Proceed anyway to avoid losing the client", "B": "Decline the service and recommend the client consult a physician/dermatologist first", "C": "Guess and hope for the best", "D": "Apply a stronger chemical to \"fix\" it"}, "answer": "B"}, {"id": 81, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Which of the following is considered a primary lesion (an original, uncomplicated skin change)?", "options": {"A": "Scar", "B": "Papule", "C": "Crust", "D": "Excoriation"}, "answer": "B"}, {"id": 82, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Scabies is caused by:", "options": {"A": "A fungus", "B": "A parasitic mite", "C": "A virus", "D": "A bacterial infection"}, "answer": "B"}, {"id": 83, "section": "Skin, Scalp Disorders & Client Consultation", "question": "Psoriasis, while chronic and sometimes cosmetically similar to dandruff, differs in that it:", "options": {"A": "Is contagious and requires immediate referral in all cases", "B": "Is generally not contagious but may still warrant caution and gentle handling during services", "C": "Is caused by lice", "D": "Cannot be present on the scalp"}, "answer": "B"}, {"id": 84, "section": "Skin, Scalp Disorders & Client Consultation", "question": "During intake, if a client discloses a recent chemotherapy treatment, a stylist should be especially mindful of:", "options": {"A": "Nothing different from any other client", "B": "Scalp sensitivity, hair fragility, and appropriate gentle product/technique choices", "C": "Applying the strongest chemical available", "D": "Refusing all future service permanently"}, "answer": "B"}, {"id": 85, "section": "Georgia State Law & Salon Regulations", "question": "The Georgia Board of Cosmetology and Barbers falls under which state umbrella agency structure?", "options": {"A": "Georgia Secretary of State's Professional Licensing Boards Division", "B": "Georgia Department of Agriculture", "C": "Georgia Department of Transportation", "D": "Georgia Department of Education"}, "answer": "A"}, {"id": 86, "section": "Georgia State Law & Salon Regulations", "question": "Which of the following would NOT typically be regulated by the Georgia Board of Cosmetology and Barbers?", "options": {"A": "Cosmetologists", "B": "Estheticians", "C": "Licensed physicians", "D": "Nail technicians"}, "answer": "C"}, {"id": 87, "section": "Georgia State Law & Salon Regulations", "question": "A candidate applying for a Georgia cosmetology license must generally pass:", "options": {"A": "No exam at all", "B": "Both a written/theory exam and a practical skills exam (or as currently required by the board)", "C": "Only an interview", "D": "A physical fitness test"}, "answer": "B"}, {"id": 88, "section": "Georgia State Law & Salon Regulations", "question": "If a Georgia licensee's certificate is lost or destroyed, they should:", "options": {"A": "Do nothing", "B": "Request a duplicate/replacement from the state board per its procedures", "C": "Assume they can no longer practice", "D": "Retake the full exam"}, "answer": "B"}, {"id": 89, "section": "Georgia State Law & Salon Regulations", "question": "Georgia salons must generally ensure that towels and linens used on clients are:", "options": {"A": "Reused without washing", "B": "Freshly laundered/clean for each client and not shared unsanitized", "C": "Only replaced weekly", "D": "Optional to launder"}, "answer": "B"}, {"id": 90, "section": "Georgia State Law & Salon Regulations", "question": "A Georgia licensee practicing a service outside their specific license category (e.g., a nail tech performing hair coloring) is:", "options": {"A": "Acceptable if the client consents", "B": "Practicing outside their legal scope, which is a violation", "C": "Encouraged for cross-training", "D": "Required by law"}, "answer": "B"}, {"id": 91, "section": "Georgia State Law & Salon Regulations", "question": "The Georgia Board of Cosmetology and Barbers has authority to do all of the following EXCEPT:", "options": {"A": "Issue and renew licenses", "B": "Investigate complaints and discipline licensees", "C": "Set federal minimum wage", "D": "Establish sanitation and safety rules for licensees"}, "answer": "C"}, {"id": 92, "section": "Georgia State Law & Salon Regulations", "question": "If a salon in Georgia fails a state sanitation inspection, likely consequences include:", "options": {"A": "A congratulatory notice", "B": "Required corrective action, possible fines, or license consequences", "C": "Automatic closure with no recourse", "D": "No consequence at all"}, "answer": "B"}, {"id": 93, "section": "Georgia State Law & Salon Regulations", "question": "Apprenticeship programs, where allowed under Georgia law, must generally be:", "options": {"A": "Informal with no oversight", "B": "Registered/approved and supervised according to board requirements", "C": "Entirely online with no supervision", "D": "Optional documentation only"}, "answer": "B"}, {"id": 94, "section": "Georgia State Law & Salon Regulations", "question": "A cosmetology license issued in Georgia is:", "options": {"A": "Valid nationwide automatically", "B": "Valid within Georgia, with other states handled through their own reciprocity rules", "C": "Valid only in the licensee's home county", "D": "Permanent and never needs renewal"}, "answer": "B"}, {"id": 95, "section": "Georgia State Law & Salon Regulations", "question": "Which best describes the consequence of allowing a license to lapse (not renewing on time) in Georgia?", "options": {"A": "No issue; the license remains valid indefinitely", "B": "The licensee may need to complete reinstatement requirements set by the board before practicing again", "C": "Automatic permanent revocation with no path to reinstatement", "D": "It has zero bearing on legal practice status"}, "answer": "B"}, {"id": 96, "section": "Georgia State Law & Salon Regulations", "question": "Salons in Georgia are generally required to post/display which of the following for clients and inspectors to see?", "options": {"A": "Owner's home address", "B": "Valid licenses (individual and/or shop) as required by the board", "C": "Client personal data", "D": "Nothing is required to be posted"}, "answer": "B"}, {"id": 97, "section": "Georgia State Law & Salon Regulations", "question": "The overarching purpose of state cosmetology boards, including Georgia's, is to:", "options": {"A": "Limit the number of licensed professionals to reduce competition", "B": "Protect public health and safety by setting and enforcing minimum standards", "C": "Control salon décor", "D": "Set uniform pricing across the industry"}, "answer": "B"}, {"id": 98, "section": "Georgia State Law & Salon Regulations", "question": "Georgia sanitation rules regarding disposal of sharp, single-use items (like razors) typically require:", "options": {"A": "Reuse after rinsing", "B": "Proper disposal in a sharps container to prevent injury/contamination", "C": "Storage for future use", "D": "No special disposal method"}, "answer": "B"}, {"id": 99, "section": "Georgia State Law & Salon Regulations", "question": "If a client files a complaint against a Georgia-licensed cosmetologist, the complaint is generally handled by:", "options": {"A": "The salon owner exclusively with no state involvement", "B": "The Georgia Board of Cosmetology and Barbers investigation/complaint process", "C": "Local police only", "D": "No process exists for complaints"}, "answer": "B"}, {"id": 100, "section": "Georgia State Law & Salon Regulations", "question": "Understanding Georgia cosmetology law and sanitation rules is tested on the licensing exam primarily because:", "options": {"A": "It is a formality with no real purpose", "B": "Practitioners need working knowledge of legal/safety standards to protect clients and practice lawfully", "C": "It is unrelated to practicing cosmetology", "D": "It only matters for salon owners, not individual stylists"}, "answer": "B"}]}];